```bash
sed -i "/if (isa<CatchPadInst>(Pad->getParentPad()))/,/return false;/a \ 
  // We can't remove the cleanuppad if it's the unwind destination for an
  // invoke.  The logic for finding the matching cleanupret would be too
  // complex.  This is a rare case, so we'll just miss the optimization.
  for (BasicBlock *Pred : predecessors(PadBB)) {
    TerminatorInst *Term = Pred->getTerminator();
    if (isa<InvokeInst>(Term))
      return false;
  }
" llvm/lib/Transforms/Utils/SimplifyCFG.cpp && submit-patch
```

